const input = $input.first().json.body || $input.first().json;

// VRF — GUARD + VALIDATE
const isValidUUID = (v) => /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(v);
const bookingId = input.old_booking_id || input.booking_id;

let isValid = true;
let error_message = null;

if (!bookingId || !isValidUUID(bookingId)) {
  isValid = false;
  error_message = 'Invalid or missing booking_id (UUID required)';
}
if (isValid && !input.new_start_time) {
  isValid = false;
  error_message = 'Missing required field: new_start_time';
}

const chatId = parseInt(input.chat_id);

return [{
  json: {
    isValid,
    error_message,
    chat_id: isNaN(chatId) ? null : chatId,
    booking_id: bookingId,
    old_booking_id: bookingId,
    start_time: input.new_start_time,
    provider_id: parseInt(input.provider_id) || 1,
    service_id: parseInt(input.service_id) || 1,
    user_email: input.user_email || '',
    user_name: input.user_name || 'Paciente'
  }
}];

// Format Reschedule Response
const cancelResult = $node["Step 1: Cancel Old"]?.json || {};
const createResult = $node["Step 2: Create New"]?.json || {};

return [{
  json: {
    success: createResult.success === true,
    error_code: createResult.error_code,
    error_message: createResult.error_message,
    data: {
      old_booking_id: cancelResult.data?.booking_id,
      old_booking_code: cancelResult.data?.booking_code,
      new_booking_id: createResult.data?.booking_id,
      new_booking_code: createResult.data?.booking_code,
      status: createResult.success ? 'CONFIRMED' : 'FAILED'
    },
    _meta: { 
      source: "DB_Reschedule_Booking", 
      timestamp: new Date().toISOString(),
      version: "1.1.0"
    }
  }
}];

return [{
  json: {
    success: false,
    error_code: "VALIDATION_ERROR",
    error_message: $json.error_message,
    data: null,
    _meta: { source: "DB_Reschedule_Booking", timestamp: new Date().toISOString(), version: "1.0.0" }
  }
}];

// 📤 STANDARD CONTRACT OUTPUT (O02)
// Retorna esquema unificado para todos los workflows

const result = $input.first()?.json || {};

return [{
  json: {
    success: result.success !== false,
    error_code: result.success === false ? (result.error_code || 'UNKNOWN_ERROR') : null,
    error_message: result.success === false ? (result.error_message || 'An error occurred') : null,
    data: result.data || null,
    _meta: {
      source: 'DB_RESCHEDULE_BOOKING',
      workflow_id: 'DB_RESCHEDULE_BOOKING',
      timestamp: new Date().toISOString(),
      version: '4.3.1'
    }
  }
}];

const buildData = $('Build Secure JSON').first().json;
return [{
  json: {
    chat_id: buildData.chat_id,
    start_time: buildData.start_time,
    provider_id: buildData.provider_id,
    service_id: buildData.service_id,
    user_name: buildData.user_name,
    user_email: buildData.user_email
  }
}];
